// Deadline clamp (A8): release = earlier of hold expiry (4 days,
// uniform across free and paid paths) or 24h before the due date.
// Never releases after the deadline renders it useless.

const fs = require('fs');
const path = require('path');

let allEntries = [];
try { allEntries = JSON.parse(fs.readFileSync(path.join('Shared', 'intake_log.json'), 'utf8')); } catch (e) {}

const ready = [];
const now = Date.now();
const HOLD_MS = 4 * 24 * 60 * 60 * 1000;

for (const entry of allEntries) {
  if (!['nda_signed', 'payment_confirmed'].includes(entry.status)) continue;
  if (entry.released) continue;

  const holdStart = new Date(entry.status === 'payment_confirmed' ? entry.payment_confirmed_at : entry.nda_signed_at).getTime();
  const holdExpiry = holdStart + HOLD_MS;

  let dueDate = null;
  try {
    const doc = JSON.parse(fs.readFileSync(path.join('Working', entry.project_prefix, 'project_document.json'), 'utf8'));
    dueDate = doc.deadline && doc.deadline.due_date_parsed ? new Date(doc.deadline.due_date_parsed).getTime() : null;
  } catch (e) {}

  const deadlineBuffer = dueDate ? dueDate - (24 * 60 * 60 * 1000) : Infinity;
  const releaseAt = Math.min(holdExpiry, deadlineBuffer);

  if (now >= releaseAt) {
    ready.push(entry);
  }
}

return ready.map(e => ({ json: e }));

const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const token = crypto.randomBytes(24).toString('hex');
const tier = $json.status === 'payment_confirmed' ? $json.tier_paid : 'lowest';

let tokens = [];
try { tokens = JSON.parse(fs.readFileSync(path.join('Shared', 'tokens.json'), 'utf8')); } catch (e) {}
tokens.push({ token, project_prefix: $json.project_prefix, contact_hash: $json.contact_hash, tier, issued_at: new Date().toISOString() });
fs.writeFileSync(path.join('Shared', 'tokens.json'), JSON.stringify(tokens, null, 2), 'utf8');

return [{ json: { ...$json, token, tier } }];

const fs = require('fs');
const path = require('path');
let entries = JSON.parse(fs.readFileSync(path.join('Shared', 'intake_log.json'), 'utf8'));
entries = entries.map(e => e.contact_hash === $json.contact_hash && e.project_prefix === $json.project_prefix ? { ...e, released: true, released_at: new Date().toISOString() } : e);
fs.writeFileSync(path.join('Shared', 'intake_log.json'), JSON.stringify(entries, null, 2), 'utf8');
return [{ json: $json }];
